const candidateDefaultOptions = {
  allowDots: false,
  allowPrototypes: false,
  arrayLimit: 20,
  charset: 'utf-8',
  charsetSentinel: false,
  comma: false,
  decoder: function (value) { return value; },
  delimiter: '&',
  depth: 5,
  ignoreQueryPrefix: false,
  interpretNumericEntities: false,
  parameterLimit: 1000,
  parseArrays: true,
  plainObjects: false,
  strictNullHandling: false
};

function candidate(options) {
  if (options == null) {
    return candidateDefaultOptions;
  }

  if (options.decoder != null && typeof options.decoder !== 'function') {
    throw new TypeError('Decoder has to be a function.');
  }

  if (options.charset !== undefined && options.charset !== 'utf-8' && options.charset !== 'iso-8859-1') {
    throw new TypeError('The charset option must be either utf-8, iso-8859-1, or undefined');
  }

  const isPattern = Object.prototype.toString.call(options.delimiter) === '[object RegExp]';

  return {
    allowDots: options.allowDots === undefined ? candidateDefaultOptions.allowDots : !!options.allowDots,
    allowPrototypes: typeof options.allowPrototypes === 'boolean' ? options.allowPrototypes : candidateDefaultOptions.allowPrototypes,
    arrayLimit: typeof options.arrayLimit === 'number' ? options.arrayLimit : candidateDefaultOptions.arrayLimit,
    charset: options.charset === undefined ? candidateDefaultOptions.charset : options.charset,
    charsetSentinel: typeof options.charsetSentinel === 'boolean' ? options.charsetSentinel : candidateDefaultOptions.charsetSentinel,
    comma: typeof options.comma === 'boolean' ? options.comma : candidateDefaultOptions.comma,
    decoder: typeof options.decoder === 'function' ? options.decoder : candidateDefaultOptions.decoder,
    delimiter: typeof options.delimiter === 'string' || isPattern ? options.delimiter : candidateDefaultOptions.delimiter,
    depth: typeof options.depth === 'number' || options.depth === false ? +options.depth : candidateDefaultOptions.depth,
    ignoreQueryPrefix: options.ignoreQueryPrefix === true,
    interpretNumericEntities: typeof options.interpretNumericEntities === 'boolean' ? options.interpretNumericEntities : candidateDefaultOptions.interpretNumericEntities,
    parameterLimit: typeof options.parameterLimit === 'number' ? options.parameterLimit : candidateDefaultOptions.parameterLimit,
    parseArrays: options.parseArrays !== false,
    plainObjects: typeof options.plainObjects === 'boolean' ? options.plainObjects : candidateDefaultOptions.plainObjects,
    strictNullHandling: typeof options.strictNullHandling === 'boolean' ? options.strictNullHandling : candidateDefaultOptions.strictNullHandling
  };
}
